# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from typing import Dict, List, Set
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str

@dataclass
class Player:
    id: str
    username: str
    inventory: Dict[str, int]
    websocket: websockets.WebSocketServerProtocol

class MMOGameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.trade_requests: Dict[str, Dict] = {}
        self.lock = asyncio.Lock()
        
    async def register_player(self, websocket, username):
        player_id = str(uuid.uuid4())
        player = Player(player_id, username, {}, websocket)
        self.players[player_id] = player
        await self.send_message(websocket, {
            "type": "player_registered",
            "player_id": player_id
        })
        return player_id
        
    async def unregister_player(self, player_id):
        if player_id in self.players:
            del self.players[player_id]
            
    async def send_message(self, websocket, message):
        try:
            await websocket.send(json.dumps(message))
        except:
            pass
            
    async def handle_message(self, websocket, message_str):
        try:
            message = json.loads(message_str)
            msg_type = message.get("type")
            
            if msg_type == "register":
                player_id = await self.register_player(websocket, message.get("username"))
                await self.send_message(websocket, {
                    "type": "registration_success",
                    "player_id": player_id
                })
                
            elif msg_type == "get_inventory":
                player_id = message.get("player_id")
                if player_id in self.players:
                    player = self.players[player_id]
                    await self.send_message(websocket, {
                        "type": "inventory_response",
                        "inventory": player.inventory
                    })
                    
            elif msg_type == "trade_request":
                await self.handle_trade_request(message)
                
            elif msg_type == "trade_response":
                await self.handle_trade_response(message)
                
            elif msg_type == "item_transfer":
                await self.handle_item_transfer(message)
                
        except Exception as e:
            print(f"Error handling message: {e}")
            
    async def handle_trade_request(self, message):
        from_player_id = message.get("from_player_id")
        to_player_id = message.get("to_player_id")
        item_id = message.get("item_id")
        quantity = message.get("quantity", 1)
        
        if from_player_id not in self.players or to_player_id not in self.players:
            return
            
        if item_id not in self.items:
            return
            
        item = self.items[item_id]
        if item.owner_id != from_player_id:
            return
            
        if from_player_id == to_player_id:
            return
            
        trade_id = str(uuid.uuid4())
        self.trade_requests[trade_id] = {
            "from_player_id": from_player_id,
            "to_player_id": to_player_id,
            "item_id": item_id,
            "quantity": quantity,
            "timestamp": datetime.now().isoformat()
        }
        
        to_player = self.players[to_player_id]
        await self.send_message(to_player.websocket, {
            "type": "trade_offer",
            "trade_id": trade_id,
            "from_player_id": from_player_id,
            "item_id": item_id,
            "quantity": quantity
        })
        
    async def handle_trade_response(self, message):
        trade_id = message.get("trade_id")
        accepted = message.get("accepted", False)
        
        if trade_id not in self.trade_requests:
            return
            
        trade = self.trade_requests[trade_id]
        from_player_id = trade["from_player_id"]
        to_player_id = trade["to_player_id"]
        item_id = trade["item_id"]
        quantity = trade["quantity"]
        
        if accepted:
            await self.execute_trade(from_player_id, to_player_id, item_id, quantity)
            
        del self.trade_requests[trade_id]
        
        from_player = self.players[from_player_id]
        to_player = self.players[to_player_id]
        
        await self.send_message(from_player.websocket, {
            "type": "trade_result",
            "trade_id": trade_id,
            "accepted": accepted
        })
        
        if accepted:
            await self.send_message(to_player.websocket, {
                "type": "trade_completed",
                "trade_id": trade_id,
                "from_player_id": from_player_id,
                "item_id": item_id,
                "quantity": quantity
            })
            
    async def execute_trade(self, from_player_id, to_player_id, item_id, quantity):
        async with self.lock:
            item = self.items[item_id]
            if item.owner_id != from_player_id:
                return
                
            # Update item ownership
            item.owner_id = to_player_id
            
            # Update inventories
            from_player = self.players[from_player_id]
            to_player = self.players[to_player_id]
            
            if item_id in from_player.inventory:
                from_player.inventory[item_id] -= quantity
                if from_player.inventory[item_id] <= 0:
                    del from_player.inventory[item_id]
                    
            if item_id in to_player.inventory:
                to_player.inventory[item_id] += quantity
            else:
                to_player.inventory[item_id] = quantity
                
            # Broadcast inventory updates
            await self.broadcast_inventory_update(from_player_id)
            await self.broadcast_inventory_update(to_player_id)
            
    async def handle_item_transfer(self, message):
        from_player_id = message.get("from_player_id")
        to_player_id = message.get("to_player_id")
        item_id = message.get("item_id")
        quantity = message.get("quantity", 1)
        
        if from_player_id not in self.players or to_player_id not in self.players:
            return
            
        if item_id not in self.items:
            return
            
        item = self.items[item_id]
        if item.owner_id != from_player_id:
            return
            
        if from_player_id == to_player_id:
            return
            
        async with self.lock:
            # Update item ownership
            item.owner_id = to_player_id
            
            # Update inventories
            from_player = self.players[from_player_id]
            to_player = self.players[to_player_id]
            
            if item_id in from_player.inventory:
                from_player.inventory[item_id] -= quantity
                if from_player.inventory[item_id] <= 0:
                    del from_player.inventory[item_id]
                    
            if item_id in to_player.inventory:
                to_player.inventory[item_id] += quantity
            else:
                to_player.inventory[item_id] = quantity
                
            # Broadcast inventory updates
            await self.broadcast_inventory_update(from_player_id)
            await self.broadcast_inventory_update(to_player_id)
            
    async def broadcast_inventory_update(self, player_id):
        player = self.players[player_id]
        await self.send_message(player.websocket, {
            "type": "inventory_update",
            "inventory": player.inventory
        })
        
    async def start_server(self, host='localhost', port=8765):
        server = await websockets.serve(
            self.handle_connection,
            host,
            port
        )
        print(f"Server started on {host}:{port}")
        await server.wait_closed()
        
    async def handle_connection(self, websocket, path):
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            # Remove player if disconnected
            for player_id, player in list(self.players.items()):
                if player.websocket == websocket:
                    await self.unregister_player(player_id)
                    break

# Create and start the server
async def main():
    server = MMOGameServer()
    await server.start_server()

if __name__ == "__main__":
    asyncio.run(main())